// ARES Agent Connector
// Orchestrates agent communication between workers, supervisors, and clients
// Version: 2.0 | Updated: 2026
// Author: Ash / Rank Higher Media + Imajery

const { 
  SUPERVISOR_MAX_RETRIES,
  ACTOR_CRITIC_TURNS,
  ACTOR_CRITIC_ENABLED,
} = require('./memory_config');

const { 
  runOllamaWorker,
  runSupervisor,
  // ... other existing imports
} = require('./agent_functions');

const fs = require('fs');
const fetch = require('node-fetch'); // For Ollama API calls

// NEW: Actor-Critic Loop Implementation
async function runActorCriticLoop(taskContent, contextPacket, outboxFile, researchFiles, supervisorFeedbackFromTask, routedModel) {
  let currentDraft = '';
  let score = 0;
  let issues = [];
  let suggestion = '';

  for (let turn = 1; turn <= ACTOR_CRITIC_TURNS; turn++) {
    // Build Actor prompt (original for turn 1, with feedback for subsequent turns)
    let actorPrompt = taskContent;
    if (turn > 1) {
      actorPrompt += `\n\nCRITIC FEEDBACK (turn ${turn-1}):\nScore: ${score}/10\nIssues: ${issues.join(', ')}\nRequired revision: ${suggestion}\n\nRevise your output to address all issues above.`;
    }

    // Actor drafts output (same as current runOllamaWorker)
    await runOllamaWorker(actorPrompt, contextPacket, outboxFile, supervisorFeedbackFromTask, researchFiles, routedModel);

    // Read current draft from file
    currentDraft = fs.readFileSync(outboxFile, 'utf8');

    // Skip Critic review after final turn
    if (turn >= ACTOR_CRITIC_TURNS) break;

    // Critic review (gemma3:12b)
    const criticPrompt = `You are a Critic agent in a multi-turn Actor-Critic debate.\n\nOriginal task:\n${taskContent}\n\nActor's current draft:\n${currentDraft}\n\nYour job: identify specific improvements only. Be brief and direct.\nFocus on: completeness, correctness, edge cases missed, quality issues.\n\nRespond with JSON only:\n{\n  "score": 8,\n  "issues": ["..."],\n  "suggestion": ".."\n}`;

    try {
      const criticResponse = await callOllama('gemma3:12b', criticPrompt, { timeout: 60000 });
      const criticData = JSON.parse(criticResponse);

      score = criticData.score;
      issues = criticData.issues;
      suggestion = criticData.suggestion;

      // Early termination if draft is good
      if (score >= 9 || issues.length === 0) {
        console.log(`🎭 Actor-Critic turn ${turn}/${ACTOR_CRITIC_TURNS} — score: ${score}/10 — no issues`);
        break;
      }

      console.log(`🎭 Actor-Critic turn ${turn}/${ACTOR_CRITIC_TURNS} — score: ${score}/10 — issues: ${issues.join(', ')}`);
    } catch (err) {
      console.error(`🎭 Critic call failed (turn ${turn}): ${err.message}`);
      break; // Skip remaining turns on failure
    }
  }

  return currentDraft;
}

// Helper for Ollama API calls
async function callOllama(model, prompt, options = {}) {
  const url = 'http://localhost:11434/api/generate';
  const body = {
    model: model,
    prompt: prompt,
    stream: false,
    options: { temperature: 0.1 }
  };

  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
    timeout: options.timeout || 30000
  });

  if (!response.ok) {
    throw new Error(`Ollama API error: ${response.status}`);
  }

  const data = await response.json();
  return data.response;
}

